urlset:
{{- range where site.RegularPages "Type" "event" }}
  {{- $lm := .Lastmod -}}
  {{- $when := "" -}}
  {{- if $lm.Before $cutoff -}}
    {{- $when = $buildtime -}}
  {{- else -}}
    {{- $when = $lm.Format "2006-01-02T15:04:05-07:00" -}}
  {{- end }}

    {{ .Permalink }}
    {{ $when | safeHTML }}
    weekly
    0.8

{{- end }}
